#include <iostream>

int main() {
  int* ptr = new int;
  *ptr = 42;
  std::cout << "Dynamic value: " << *ptr << std::endl;
  delete ptr;
  return 0;
}
// Output:
// Dynamic value: 42

#include <iostream>

int main() {
  int* arr = new int[3];
  arr[0] = 10;
  arr[1] = 20;
  arr[2] = 30;
  std::cout << "First element: " << arr[0] << std::endl;
  std::cout << "Second element: " << arr[1] << std::endl;
  delete[] arr;
  return 0;
}
// Output:
// First element: 10
// Second element: 20

#include <iostream>

int main() {
  int* ptr = new int;
  *ptr = 100;
  std::cout << "Value: " << *ptr << std::endl;
  delete ptr;
  // delete çağrılmasa, yaddaş sızması olardı
  return 0;
}
// Output:
// Value: 100

#include <iostream>

int* createArray() {
  int* arr = new int[2];
  arr[0] = 5;
  arr[1] = 10;
  return arr;
}

int main() {
  int* result = createArray();
  std::cout << "First element: " << result[0] << std::endl;
  delete[] result;
  return 0;
}
// Output:
// First element: 5

